/**
 * @summary List milestones
 */
export const getGetMilestonesUrl = (params?: GetMilestonesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/milestones?${stringifiedParams}`
    : `/api/milestones`;
};

export const getMilestones = async (
  params?: GetMilestonesParams,
  options?: RequestInit,
): Promise<Milestone[]> => {
  return customFetch<Milestone[]>(getGetMilestonesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetMilestonesQueryKey = (params?: GetMilestonesParams) => {
  return [`/api/milestones`, ...(params ? [params] : [])] as const;
};

export const getGetMilestonesQueryOptions = <
  TData = Awaited<ReturnType<typeof getMilestones>>,
  TError = ErrorType<unknown>,
>(
  params?: GetMilestonesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getMilestones>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetMilestonesQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getMilestones>>> = ({
    signal,
  }) => getMilestones(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getMilestones>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetMilestonesQueryResult = NonNullable<
  Awaited<ReturnType<typeof getMilestones>>
>;
export type GetMilestonesQueryError = ErrorType<unknown>;

/**
 * @summary List milestones
 */

export function useGetMilestones<
  TData = Awaited<ReturnType<typeof getMilestones>>,
  TError = ErrorType<unknown>,
>(
  params?: GetMilestonesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getMilestones>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetMilestonesQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

